     1→// Mock Interview component — full AI video interview with voice mode
     2→// Extracted from ai-coaching.tsx for maintainability
     3→
     4→import { useState, useRef, useEffect } from 'react'
     5→import { apiCall, getToken } from '@/lib/api'
     6→import { Card, CardContent } from '@/components/ui/card'
     7→import { Button } from '@/components/ui/button'
     8→import { Badge } from '@/components/ui/badge'
     9→import { Textarea } from '@/components/ui/textarea'
    10→import {
    11→  Brain, Trophy, TrendingUp, Sparkles,
    12→  Video, VideoOff, Mic, MicOff, Camera, Eye,
    13→  Volume2, AlertCircle, ChevronDown, ChevronUp, Square,
    14→  User, Monitor, MessageSquare, Star, Zap,
    15→  Send, Briefcase, StopCircle, Loader2, Plus,
    16→  History, FileText,
    17→} from 'lucide-react'
    18→
    19→import type {
    20→  MockConversationTurn, MockSession, MockSessionSummary, SessionFeedback,
    21→} from './coaching-types'
    22→import {
    23→  categoryConfig, scoreColor, scoreBg, scoreLabel, ScoreBar,
    24→} from './coaching-utils'
    25→
    26→
    27→interface MockInterviewProps {
    28→  mockPastSessions: MockSessionSummary[]
    29→  onSessionComplete: () => void
    30→}
    31→
    32→export function MockInterview({ mockPastSessions, onSessionComplete }: MockInterviewProps) {
    33→  // Mock Interview state
    34→  const [mockTargetRole, setMockTargetRole] = useState('')
    35→  const [mockJobDescription, setMockJobDescription] = useState('')
    36→  const [mockStarting, setMockStarting] = useState(false)
    37→  const [mockSession, setMockSession] = useState<MockSession | null>(null)
    38→  const mockSessionRef = useRef<MockSession | null>(null)
    39→  const [mockResponseText, setMockResponseText] = useState('')
    40→  const [mockSending, setMockSending] = useState(false)
    41→  const [mockEnding, setMockEnding] = useState(false)
    42→  const [mockFeedback, setMockFeedback] = useState<SessionFeedback | null>(null)
    43→  const [mockShowSetup, setMockShowSetup] = useState(false)
    44→  const chatEndRef = useRef<HTMLDivElement>(null)
    45→
    46→  // Voice interview state
    47→  const [voiceMode, setVoiceMode] = useState(false)
    48→  const voiceModeRef = useRef(false)
    49→  const [aiSpeaking, setAiSpeaking] = useState(false)
    50→  const [candidateRecording, setCandidateRecording] = useState(false)
    51→  const candidateRecordingRef = useRef(false)
    52→  const [voiceProcessing, setVoiceProcessing] = useState(false)
    53→  const voiceProcessingRef = useRef(false)
    54→  const [silenceTimer, setSilenceTimer] = useState<number>(0)
    55→  const [voiceError, setVoiceError] = useState<string | null>(null)
    56→  const aiAudioRef = useRef<HTMLAudioElement | null>(null)
    57→  const voiceRecorderRef = useRef<MediaRecorder | null>(null)
    58→  const voiceChunksRef = useRef<Blob[]>([])
    59→  const voiceStreamRef = useRef<MediaStream | null>(null)
    60→  const silenceIntervalRef = useRef<ReturnType<typeof setInterval> | null>(null)
    61→  const analyserRef = useRef<AnalyserNode | null>(null)
    62→  const silenceCountRef = useRef<number>(0)
    63→
    64→  // Mock interview camera state
    65→  const [mockCameraReady, setMockCameraReady] = useState(false)
    66→  const [mockCameraError, setMockCameraError] = useState<string | null>(null)
    67→  const mockVideoRef = useRef<HTMLVideoElement>(null)
    68→  const mockStreamRef = useRef<MediaStream | null>(null)
    69→  const [showTranscript, setShowTranscript] = useState(false)
    70→
    71→  // Enhanced mock interview: AudioContext, frame capture, live transcript
    72→  const audioCtxRef = useRef<AudioContext | null>(null)
    73→  const mockCanvasRef = useRef<HTMLCanvasElement | null>(null)
    74→  const mockFramesRef = useRef<string[]>([])
    75→  const mockPerQuestionFramesRef = useRef<string[]>([])
    76→  const mockQuestionStartTimeRef = useRef<number>(Date.now())
    77→  const mockFrameIntervalRef = useRef<ReturnType<typeof setInterval> | null>(null)
    78→  const [mockLiveTranscript, setMockLiveTranscript] = useState('')
    79→  const mockLiveTranscriptRef = useRef('')
    80→  const mockRecognitionRef = useRef<any>(null)
    81→  const mockAudioSourceRef = useRef<AudioBufferSourceNode | null>(null)
    82→  const voiceRetryCountRef = useRef<number>(0)
    83→
    84→  // Real-time body language indicators
    85→  const [bodyLanguageIndicators, setBodyLanguageIndicators] = useState<{
    86→    eye_contact: string; posture: string; confidence: string; expression: string; last_updated: string
    87→  } | null>(null)
    88→  const bodyLanguageIntervalRef = useRef<ReturnType<typeof setInterval> | null>(null)
    89→
    90→  // Feedback expandable sections
    91→  const [expandedSection, setExpandedSection] = useState<string | null>('mock-content')
    92→
    93→  // Keep mockSessionRef in sync
    94→  useEffect(() => { mockSessionRef.current = mockSession }, [mockSession])
    95→
    96→  // Attach camera stream to video element after render
    97→  useEffect(() => {
    98→    if (mockCameraReady && mockStreamRef.current && mockSession && mockSession.status === 'in_progress') {
    99→      const v = mockVideoRef.current
   100→      if (v && !v.srcObject) {
   101→        console.log('[camera] Attaching stream to video element (deferred)')
   102→        v.srcObject = mockStreamRef.current
   103→        v.play().catch(() => { v.play().catch(() => {}) })
   104→      }
   105→    }
   106→  }, [mockCameraReady, mockSession])
   107→
   108→  // When voice mode is enabled and session starts, play first message
   109→  useEffect(() => {
   110→    if (voiceMode && mockSession && mockSession.status === 'in_progress' && mockSession.conversation.length > 0) {
   111→      const lastMsg = mockSession.conversation[mockSession.conversation.length - 1]
   112→      if (lastMsg.role === 'interviewer' && !aiSpeaking && !candidateRecording && !voiceProcessing) {
   113→        if (mockSession.conversation.length === 1) {
   114→          playInterviewerAudio(lastMsg.text)
   115→        }
   116→      }
   117→    }
   118→  }, [voiceMode, mockSession?.id]) // eslint-disable-line react-hooks/exhaustive-deps
   119→
   120→  // Auto-dismiss voice errors after 10 seconds
   121→  useEffect(() => {
   122→    if (voiceError) {
   123→      const t = setTimeout(() => setVoiceError(null), 10000)
   124→      return () => clearTimeout(t)
   125→    }
   126→  }, [voiceError])
   127→
   128→  // Cleanup on unmount
   129→  useEffect(() => {
   130→    return () => {
   131→      stopVoiceMode()
   132→      stopMockCamera()
   133→      stopMockFrameCapture()
   134→      stopMockSpeechRecognition()
   135→      if (audioCtxRef.current && audioCtxRef.current.state !== 'closed') {
   136→        try { audioCtxRef.current.close() } catch (_) {}
   137→      }
   138→    }
   139→  }, [])
   140→
   141→  // ===== CAMERA FUNCTIONS =====
   142→
   143→  async function startMockCamera() {
   144→    try {
   145→      setMockCameraError(null)
   146→      if (!navigator.mediaDevices?.getUserMedia) {
   147→        setMockCameraError('Camera not supported in this browser')
   148→        return
   149→      }
   150→      const constraints = [
   151→        { video: { facingMode: 'user' }, audio: true },
   152→        { video: true, audio: true },
   153→        { video: { facingMode: 'user' }, audio: false },
   154→        { video: true, audio: false },
   155→      ]
   156→      let stream: MediaStream | null = null
   157→      for (const c of constraints) {
   158→        try {
   159→          stream = await navigator.mediaDevices.getUserMedia(c)
   160→          const vt = stream.getVideoTracks()[0]
   161→          if (vt?.readyState === 'live') break
   162→          stream.getTracks().forEach(t => t.stop())
   163→          stream = null
   164→        } catch { stream = null }
   165→      }
   166→      if (!stream) {
   167→        setMockCameraError('Could not access camera')
   168→        return
   169→      }
   170→      mockStreamRef.current = stream
   171→      const v = mockVideoRef.current
   172→      if (v) {
   173→        v.srcObject = stream
   174→        try { await v.play() } catch { try { await v.play() } catch {} }
   175→      }
   176→      setMockCameraReady(true)
   177→    } catch (err: any) {
   178→      setMockCameraError(err.message || 'Camera error')
   179→    }
   180→  }
   181→
   182→  function stopMockCamera() {
   183→    if (mockStreamRef.current) {
   184→      mockStreamRef.current.getTracks().forEach(t => t.stop())
   185→      mockStreamRef.current = null
   186→    }
   187→    setMockCameraReady(false)
   188→  }
   189→
   190→  function captureMockFrame(): string | null {
   191→    if (!mockVideoRef.current) return null
   192→    if (!mockCanvasRef.current) {
   193→      mockCanvasRef.current = document.createElement('canvas')
   194→    }
   195→    const canvas = mockCanvasRef.current
   196→    const video = mockVideoRef.current
   197→    canvas.width = 320
   198→    canvas.height = 240
   199→    const ctx = canvas.getContext('2d')
   200→    if (!ctx) return null
   201→    ctx.drawImage(video, 0, 0, 320, 240)
   202→    return canvas.toDataURL('image/jpeg', 0.7)
   203→  }
   204→
   205→  function startMockFrameCapture() {
   206→    mockFramesRef.current = []
   207→    mockPerQuestionFramesRef.current = []
   208→    mockQuestionStartTimeRef.current = Date.now()
   209→    setTimeout(() => {
   210→      const frame = captureMockFrame()
   211→      if (frame) {
   212→        mockFramesRef.current.push(frame)
   213→        mockPerQuestionFramesRef.current.push(frame)
   214→      }
   215→    }, 500)
   216→    mockFrameIntervalRef.current = setInterval(() => {
   217→      const frame = captureMockFrame()
   218→      if (frame) {
   219→        if (mockFramesRef.current.length < 20) mockFramesRef.current.push(frame)
   220→        if (mockPerQuestionFramesRef.current.length < 8) mockPerQuestionFramesRef.current.push(frame)
   221→      }
   222→    }, 4000)
   223→  }
   224→
   225→  function stopMockFrameCapture() {
   226→    if (mockFrameIntervalRef.current) {
   227→      clearInterval(mockFrameIntervalRef.current)
   228→      mockFrameIntervalRef.current = null
   229→    }
   230→    if (bodyLanguageIntervalRef.current) {
   231→      clearInterval(bodyLanguageIntervalRef.current)
   232→      bodyLanguageIntervalRef.current = null
   233→    }
   234→  }
   235→
   236→  // ===== SPEECH RECOGNITION =====
   237→
   238→  function startMockSpeechRecognition() {
   239→    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition
   240→    if (!SpeechRecognition) return
   241→
   242→    const recognition = new SpeechRecognition()
   243→    recognition.continuous = true
   244→    recognition.interimResults = true
   245→    recognition.lang = 'en-US'
   246→
   247→    let finalTranscript = ''
   248→
   249→    recognition.onresult = (event: any) => {
   250→      let interim = ''
   251→      for (let i = event.resultIndex; i < event.results.length; i++) {
   252→        const result = event.results[i]
   253→        if (result.isFinal) {
   254→          finalTranscript += result[0].transcript + ' '
   255→        } else {
   256→          interim = result[0].transcript
   257→        }
   258→      }
   259→      const combined = finalTranscript + interim
   260→      setMockLiveTranscript(combined)
   261→      mockLiveTranscriptRef.current = combined
   262→    }
   263→
   264→    recognition.onerror = (event: any) => {
   265→      if (event.error === 'no-speech') {
   266→        try { recognition.start() } catch (_) {}
   267→      }
   268→    }
   269→
   270→    recognition.onend = () => {
   271→      if (candidateRecordingRef.current) {
   272→        try { recognition.start() } catch (_) {}
   273→      }
   274→    }
   275→
   276→    try {
   277→      recognition.start()
   278→      mockRecognitionRef.current = recognition
   279→    } catch (_) {}
   280→  }
   281→
   282→  function stopMockSpeechRecognition() {
   283→    if (mockRecognitionRef.current) {
   284→      try { mockRecognitionRef.current.stop() } catch (_) {}
   285→      mockRecognitionRef.current = null
   286→    }
   287→  }
   288→
   289→  function ensureAudioContext(): AudioContext {
   290→    if (!audioCtxRef.current || audioCtxRef.current.state === 'closed') {
   291→      audioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)()
   292→    }
   293→    if (audioCtxRef.current.state === 'suspended') {
   294→      audioCtxRef.current.resume()
   295→    }
   296→    return audioCtxRef.current
   297→  }
   298→
   299→  // ===== VOICE FUNCTIONS =====
   300→
   301→  function speakWithBrowserTTS(text: string): Promise<void> {
   302→    return new Promise((resolve) => {
   303→      if (!window.speechSynthesis) {
   304→        console.warn('[browser-tts] speechSynthesis not available')
   305→        resolve()
   306→        return
   307→      }
   308→      window.speechSynthesis.cancel()
   309→      const utterance = new SpeechSynthesisUtterance(text)
   310→      utterance.rate = 1.0
   311→      utterance.pitch = 1.0
   312→      utterance.volume = 1.0
   313→
   314→      let voices = window.speechSynthesis.getVoices()
   315→      if (voices.length === 0) {
   316→        window.speechSynthesis.onvoiceschanged = () => {
   317→          voices = window.speechSynthesis.getVoices()
   318→          const preferred = voices.find(v => v.lang.startsWith('en') && v.name.toLowerCase().includes('female'))
   319→            || voices.find(v => v.lang.startsWith('en') && v.name.toLowerCase().includes('samantha'))
   320→            || voices.find(v => v.lang.startsWith('en-US'))
   321→            || voices.find(v => v.lang.startsWith('en'))
   322→          if (preferred) utterance.voice = preferred
   323→        }
   324→      } else {
   325→        const preferred = voices.find(v => v.lang.startsWith('en') && v.name.toLowerCase().includes('female'))
   326→          || voices.find(v => v.lang.startsWith('en') && v.name.toLowerCase().includes('samantha'))
   327→          || voices.find(v => v.lang.startsWith('en-US'))
   328→          || voices.find(v => v.lang.startsWith('en'))
   329→        if (preferred) utterance.voice = preferred
   330→      }
   331→
   332→      const timeout = setTimeout(() => {
   333→        console.warn('[browser-tts] Safety timeout — resolving after 30s')
   334→        resolve()
   335→      }, 30000)
   336→
   337→      const keepAlive = setInterval(() => {
   338→        if (window.speechSynthesis.speaking) {
   339→          window.speechSynthesis.resume()
   340→        } else {
   341→          clearInterval(keepAlive)
   342→        }
   343→      }, 5000)
   344→
   345→      utterance.onend = () => { clearTimeout(timeout); clearInterval(keepAlive); resolve() }
   346→      utterance.onerror = (e) => { clearTimeout(timeout); clearInterval(keepAlive); console.warn('[browser-tts] error:', e); resolve() }
   347→
   348→      window.speechSynthesis.speak(utterance)
   349→      console.log('[browser-tts] Speaking via browser speechSynthesis')
   350→    })
   351→  }
   352→
   353→  async function playInterviewerAudio(text: string) {
   354→    if (!text) return
   355→    setAiSpeaking(true)
   356→    setVoiceError(null)
   357→    try {
   358→      const token = getToken()
   359→      const response = await fetch('/api/interviews/mock/tts', {
   360→        method: 'POST',
   361→        headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${token}` },
   362→        body: JSON.stringify({ text })
   363→      })
   364→
   365→      const contentType = response.headers.get('content-type') || ''
   366→
   367→      if (contentType.includes('application/json')) {
   368→        console.log('[tts-client] TTS API unavailable, falling back to browser speech synthesis')
   369→        await speakWithBrowserTTS(text)
   370→        setAiSpeaking(false)
   371→        if (voiceModeRef.current && !candidateRecordingRef.current) startVoiceRecording()
   372→        return
   373→      }
   374→
   375→      if (!response.ok) {
   376→        console.error('[tts-client] TTS failed:', response.status)
   377→        await speakWithBrowserTTS(text)
   378→        setAiSpeaking(false)
   379→        if (voiceModeRef.current && !candidateRecordingRef.current) setTimeout(() => startVoiceRecording(), 500)
   380→        return
   381→      }
   382→
   383→      const arrayBuffer = await response.arrayBuffer()
   384→      if (arrayBuffer.byteLength < 100) {
   385→        console.error('[tts-client] Audio too small:', arrayBuffer.byteLength)
   386→        await speakWithBrowserTTS(text)
   387→        setAiSpeaking(false)
   388→        if (voiceModeRef.current && !candidateRecordingRef.current) setTimeout(() => startVoiceRecording(), 500)
   389→        return
   390→      }
   391→
   392→      const ctx = ensureAudioContext()
   393→
   394→      try {
   395→        const audioBuffer = await ctx.decodeAudioData(arrayBuffer.slice(0))
   396→        if (mockAudioSourceRef.current) {
   397→          try { mockAudioSourceRef.current.stop() } catch (_) {}
   398→        }
   399→        const source = ctx.createBufferSource()
   400→        source.buffer = audioBuffer
   401→        source.connect(ctx.destination)
   402→        mockAudioSourceRef.current = source
   403→
   404→        source.onended = () => {
   405→          setAiSpeaking(false)
   406→          mockAudioSourceRef.current = null
   407→          if (voiceModeRef.current && !candidateRecordingRef.current) startVoiceRecording()
   408→        }
   409→
   410→        source.start()
   411→        console.log('[tts-client] Playing via Web Audio API')
   412→      } catch (decodeErr) {
   413→        console.warn('[tts-client] Web Audio decode failed, falling back to Audio element:', decodeErr)
   414→        const blob = new Blob([arrayBuffer], { type: 'audio/mpeg' })
   415→        const audioUrl = URL.createObjectURL(blob)
   416→        if (aiAudioRef.current) {
   417→          aiAudioRef.current.pause()
   418→          URL.revokeObjectURL(aiAudioRef.current.src)
   419→        }
   420→        const audio = new Audio(audioUrl)
   421→        aiAudioRef.current = audio
   422→        audio.onended = () => {
   423→          setAiSpeaking(false)
   424→          URL.revokeObjectURL(audioUrl)
   425→          if (voiceModeRef.current && !candidateRecordingRef.current) startVoiceRecording()
   426→        }
   427→        audio.onerror = () => {
   428→          setAiSpeaking(false)
   429→          URL.revokeObjectURL(audioUrl)
   430→          if (voiceModeRef.current && !candidateRecordingRef.current) setTimeout(() => startVoiceRecording(), 1000)
   431→        }
   432→        await audio.play()
   433→      }
   434→    } catch (err) {
   435→      console.error('[tts-client] TTS playback error:', err)
   436→      try { await speakWithBrowserTTS(text) } catch (_) {}
   437→      setAiSpeaking(false)
   438→      if (voiceModeRef.current && !candidateRecordingRef.current) setTimeout(() => startVoiceRecording(), 500)
   439→    }
   440→  }
   441→
   442→  async function startVoiceRecording() {
   443→    setVoiceError(null)
   444→    setMockLiveTranscript('')
   445→    mockLiveTranscriptRef.current = ''
   446→    try {
   447→      if (!voiceStreamRef.current) {
   448→        if (mockStreamRef.current && mockStreamRef.current.getAudioTracks().length > 0) {
   449→          const audioTrack = mockStreamRef.current.getAudioTracks()[0]
   450→          voiceStreamRef.current = new MediaStream([audioTrack])
   451→        } else {
   452→          voiceStreamRef.current = await navigator.mediaDevices.getUserMedia({ audio: true })
   453→        }
   454→      }
   455→
   456→      voiceChunksRef.current = []
   457→
   458→      const audioContext = ensureAudioContext()
   459→      const source = audioContext.createMediaStreamSource(voiceStreamRef.current)
   460→      const analyser = audioContext.createAnalyser()
   461→      analyser.fftSize = 512
   462→      source.connect(analyser)
   463→      analyserRef.current = analyser
   464→      silenceCountRef.current = 0
   465→
   466→      silenceIntervalRef.current = setInterval(() => {
   467→        if (!analyserRef.current) return
   468→        const dataArray = new Uint8Array(analyserRef.current.frequencyBinCount)
   469→        analyserRef.current.getByteFrequencyData(dataArray)
   470→        const avg = dataArray.reduce((a, b) => a + b, 0) / dataArray.length
   471→        if (avg < 8) {
   472→          silenceCountRef.current++
   473→          setSilenceTimer(Math.round(silenceCountRef.current * 0.2))
   474→          if (silenceCountRef.current >= 18) stopVoiceRecording()
   475→        } else {
   476→          silenceCountRef.current = 0
   477→          setSilenceTimer(0)
   478→        }
   479→      }, 200)
   480→
   481→      const mimeType = MediaRecorder.isTypeSupported('audio/webm;codecs=opus')
   482→        ? 'audio/webm;codecs=opus'
   483→        : MediaRecorder.isTypeSupported('audio/mp4')
   484→          ? 'audio/mp4'
   485→          : 'audio/webm'
   486→
   487→      const recorder = new MediaRecorder(voiceStreamRef.current, { mimeType })
   488→      voiceRecorderRef.current = recorder
   489→
   490→      recorder.ondataavailable = (e) => {
   491→        if (e.data.size > 0) voiceChunksRef.current.push(e.data)
   492→      }
   493→
   494→      recorder.onstop = async () => {
   495→        setCandidateRecording(false)
   496→        candidateRecordingRef.current = false
   497→        if (silenceIntervalRef.current) clearInterval(silenceIntervalRef.current)
   498→        setSilenceTimer(0)
   499→
   500→        if (voiceChunksRef.current.length === 0) return
   501→
   502→        const totalSilenceChecks = silenceCountRef.current
   503→        const currentTranscript = mockLiveTranscriptRef.current
   504→        if (totalSilenceChecks >= 16 && !currentTranscript.trim()) {
   505→          console.log('[voice] Skipping — recording was mostly silence')
   506→          setMockLiveTranscript('')
   507→          setVoiceError('No speech detected. Tap the mic button when ready to speak.')
   508→          return
   509→        }
   510→
   511→        setVoiceProcessing(true)
   512→        voiceProcessingRef.current = true
   513→        try {
   514→          const currentSession = mockSessionRef.current
   515→          if (!currentSession?.id) {
   516→            console.error('[voice] No active session — cannot send voice response')
   517→            setVoiceError('No active interview session. Please restart.')
   518→            setVoiceProcessing(false)
   519→            voiceProcessingRef.current = false
   520→            return
   521→          }
   522→
   523→          const audioBlob = new Blob(voiceChunksRef.current, { type: mimeType })
   524→
   525→          const voicePerQuestionFrames = [...mockPerQuestionFramesRef.current]
   526→          const voiceQuestionDuration = Math.round((Date.now() - mockQuestionStartTimeRef.current) / 1000)
   527→          mockPerQuestionFramesRef.current = []
   528→          mockQuestionStartTimeRef.current = Date.now()
   529→
   530→          const formData = new FormData()
   531→          const ext = mimeType.includes('mp4') ? 'mp4' : mimeType.includes('ogg') ? 'ogg' : 'webm'
   532→          formData.append('audio', audioBlob, `recording.${ext}`)
   533→          const liveTranscript = mockLiveTranscriptRef.current.trim()
   534→          if (liveTranscript.length >= 5) {
   535→            formData.append('response_text', liveTranscript)
   536→          }
   537→          if (voicePerQuestionFrames.length > 0) {
   538→            formData.append('frames_json', JSON.stringify(voicePerQuestionFrames))
   539→          }
   540→          formData.append('duration_seconds', String(voiceQuestionDuration))
   541→
   542→          const token = getToken()
   543→          const abortController = new AbortController()
   544→          const fetchTimeout = setTimeout(() => abortController.abort(), 28000)
   545→
   546→          let res: Response
   547→          try {
   548→            res = await fetch(`/api/interviews/mock/${currentSession.id}/voice-respond`, {
   549→              method: 'POST',
   550→              headers: { 'Authorization': `Bearer ${token}` },
   551→              body: formData,
   552→              signal: abortController.signal
   553→            })
   554→          } finally {
   555→            clearTimeout(fetchTimeout)
   556→          }
   557→
   558→          const data = await res.json()
   559→
   560→          if (data.success) {
   561→            voiceRetryCountRef.current = 0
   562→
   563→            const candidateMsg: MockConversationTurn = {
   564→              role: 'candidate',
   565→              text: data.transcribed_text,
   566→              timestamp: new Date().toISOString()
   567→            }
   568→            setMockSession(prev => prev ? {
   569→              ...prev,
   570→              conversation: [...prev.conversation, candidateMsg, data.interviewer_message]
   571→            } : null)
   572→            setTimeout(() => chatEndRef.current?.scrollIntoView({ behavior: 'smooth' }), 100)
   573→
   574→            if (data.interviewer_audio_base64) {
   575→              setAiSpeaking(true)
   576→              const audioData = Uint8Array.from(atob(data.interviewer_audio_base64), c => c.charCodeAt(0))
   577→              const ctx = ensureAudioContext()
   578→
   579→              try {
   580→                const audioBuffer = await ctx.decodeAudioData(audioData.buffer.slice(0))
   581→                if (mockAudioSourceRef.current) {
   582→                  try { mockAudioSourceRef.current.stop() } catch (_) {}
   583→                }
   584→                const srcNode = ctx.createBufferSource()
   585→                srcNode.buffer = audioBuffer
   586→                srcNode.connect(ctx.destination)
   587→                mockAudioSourceRef.current = srcNode
   588→                srcNode.onended = () => {
   589→                  setAiSpeaking(false)
   590→                  mockAudioSourceRef.current = null
   591→                  if (voiceModeRef.current && !data.is_wrapping_up) startVoiceRecording()
   592→                }
   593→                srcNode.start()
   594→                console.log('[voice-respond] Playing AI audio via Web Audio API')
   595→              } catch (decodeErr) {
   596→                console.warn('[voice-respond] Web Audio decode failed, fallback:', decodeErr)
   597→                const blob = new Blob([audioData], { type: 'audio/mpeg' })
   598→                const url = URL.createObjectURL(blob)
   599→                if (aiAudioRef.current) {
   600→                  aiAudioRef.current.pause()
   601→                  URL.revokeObjectURL(aiAudioRef.current.src)
   602→                }
   603→                const audio = new Audio(url)
   604→                aiAudioRef.current = audio
   605→                audio.onended = () => {
   606→                  setAiSpeaking(false)
   607→                  URL.revokeObjectURL(url)
   608→                  if (voiceModeRef.current && !data.is_wrapping_up) startVoiceRecording()
   609→                }
   610→                audio.onerror = () => {
   611→                  setAiSpeaking(false)
   612→                  URL.revokeObjectURL(url)
   613→                  if (voiceModeRef.current && !data.is_wrapping_up) setTimeout(() => startVoiceRecording(), 1000)
   614→                }
   615→                await audio.play()
   616→              }
   617→            } else {
   618→              await playInterviewerAudio(data.interviewer_message.text)
   619→            }
   620→          } else {
   621→            const errorMsg = data.error || 'Failed to process your response'
   622→            console.warn('[voice] Transcription failed:', errorMsg)
   623→            voiceRetryCountRef.current = 0
   624→            setMockLiveTranscript('')
   625→            if (errorMsg.includes("didn't catch") || errorMsg.includes('Could not transcribe')) {
   626→              setVoiceError('Could not understand your response. Tap the mic button to try again, or type your answer below.')
   627→            } else {
   628→              setVoiceError(errorMsg)
   629→            }
   630→          }
   631→        } catch (err: any) {
   632→          if (err.name === 'AbortError') {
   633→            console.warn('[voice] Request timed out after 28s')
   634→            setVoiceError('The AI is taking too long to respond. Tap the mic to try again, or type your answer below.')
   635→          } else {
   636→            setVoiceError(err.message || 'Voice processing failed. Tap the mic to try again.')
   637→            console.error('Voice response error:', err)
   638→          }
   639→        } finally {
   640→          setVoiceProcessing(false)
   641→          voiceProcessingRef.current = false
   642→        }
   643→      }
   644→
   645→      recorder.start(250)
   646→      setCandidateRecording(true)
   647→      candidateRecordingRef.current = true
   648→
   649→      setMockLiveTranscript('')
   650→      mockLiveTranscriptRef.current = ''
   651→      startMockSpeechRecognition()
   652→    } catch (err: any) {
   653→      console.error('Mic access error:', err)
   654→      setVoiceError('Microphone access denied. Please allow microphone access to use voice mode.')
   655→      setCandidateRecording(false)
