   743→  async function sendMockResponse() {
   744→    if (!mockSession || !mockResponseText.trim() || mockSending) return
   745→    const text = mockResponseText.trim()
   746→    setMockResponseText('')
   747→    setMockSending(true)
   748→
   749→    const perQuestionFrames = [...mockPerQuestionFramesRef.current]
   750→    const questionDuration = Math.round((Date.now() - mockQuestionStartTimeRef.current) / 1000)
   751→    mockPerQuestionFramesRef.current = []
   752→    mockQuestionStartTimeRef.current = Date.now()
   753→
   754→    const candidateMsg: MockConversationTurn = { role: 'candidate', text, timestamp: new Date().toISOString() }
   755→    setMockSession(prev => prev ? { ...prev, conversation: [...prev.conversation, candidateMsg] } : null)
   756→    setTimeout(() => chatEndRef.current?.scrollIntoView({ behavior: 'smooth' }), 50)
   757→
   758→    try {
   759→      const textAbort = new AbortController()
