   761→
   762→      try {
   763→        const res = await apiCall<{
   764→          success: boolean; interviewer_message: MockConversationTurn; action: string; is_wrapping_up: boolean
   765→        }>(`/interviews/mock/${mockSession.id}/respond`, {
