   769→            frames: perQuestionFrames.length > 0 ? perQuestionFrames : undefined,
   770→            duration_seconds: questionDuration
   771→          },
   772→          signal: textAbort.signal
   773→        })
   774→        if (res.success) {
   775→          setMockSession(prev => prev ? {
   776→            ...prev,
   777→            conversation: [...prev.conversation, res.interviewer_message]
   778→          } : null)
   779→          setTimeout(() => chatEndRef.current?.scrollIntoView({ behavior: 'smooth' }), 100)
   780→          if (res.interviewer_message?.text) {
   781→            playInterviewerAudio(res.interviewer_message.text)
