   786→            }, 8000)
   787→          }
   788→        }
   789→      } finally {
   790→        clearTimeout(textTimeout)
   791→      }
   792→    } catch (err: any) {
   793→      if (err.name === 'AbortError') {
   794→        setVoiceError('AI is taking too long. Please try sending your response again.')
   795→      } else {
   796→        alert(err.message || 'Failed to send response')
   797→      }
   798→    } finally {
   799→      setMockSending(false)
   800→    }
   801→  }
